import { useEffect, useState } from "react";

const WIDTH = 400;
const HEIGHT = 300;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [duck, setDuck] = useState({
    x: 0,
    y: 0,
    alive: false,
  });

  useEffect(() => {
    let running = true;
    let shot = false;

    async function gameLoop() {
      while (running) {
        shot = false;

        setDuck({
          x: Math.random() * (WIDTH - 50),
          y: Math.random() * (HEIGHT - 50),
          alive: true,
        });

        // Wait up to 1.5 seconds for the duck to be shot.
        for (let i = 0; i < 15 && !shot && running; i++) {
          await sleep(100);
        }

        if (!running) break;

        if (shot) {
          await sleep(200);
        }
      }
    }

    gameLoop();

    return () => {
      running = false;
    };
  }, []);

  function shootDuck() {
    if (duck.alive) {
		setScore((score) => score + 1);

		setDuck((duck) => ({
			...duck,
			alive: false,
		}));	
		shot = true;
	}
  }

  return (
    <main>
      <h1>🔫 Duck Hunt</h1>

      <p>Score: {score}</p>

      <article
        style={{
          position: "relative",
          width: WIDTH,
          height: HEIGHT,
          border: "2px solid currentColor",
          overflow: "hidden",
          cursor: "crosshair",
        }}
      >
        <button
          onClick={shootDuck}
          style={{
            position: "absolute",
            left: duck.x,
            top: duck.y,
            border: "none",
            background: "none",
            padding: 0,
            fontSize: "2.5rem",
            cursor: "crosshair",
          }}
        >
          {duck.alive ? "🦆" : "💥"}
        </button>
      </article>
    </main>
  );
}
